(() => {
  const defaultEngines = [
    { name: "百度", url: "https://www.baidu.com/s?wd=", img: "images/sou1.png" },
    { name: "Google", url: "https://www.google.com/search?q=", img: "images/sou2.png" },
    { name: "Bing搜索", url: "https://cn.bing.com/search?q=", img: "images/sou3.png" },
    { name: "360搜索", url: "https://www.so.com/s?q=", img: "images/sou4.png" },
    { name: "搜狗搜索", url: "https://www.sogou.com/web?query=", img: "images/sou5.png" }
  ];

  const storageKey = "searchData";
  const searchInput = document.querySelector("#txt");
  const searchButton = document.querySelector("#search-btn");
  const searchToggle = document.querySelector("#search-engine-toggle");
  const searchIcon = document.querySelector(".search-icon");
  const searchEnginePanel = document.querySelector(".search-engine");
  const searchEngineList = document.querySelector(".search-engine-list");

  if (!searchInput || !searchButton || !searchToggle || !searchIcon || !searchEnginePanel || !searchEngineList) {
    return;
  }

  const getDefaultState = () => ({
    thisSearch: defaultEngines[0].url,
    thisSearchIcon: defaultEngines[0].img,
    data: defaultEngines.map((engine) => ({ ...engine }))
  });

  const resolveActiveEngine = (candidate) => {
    if (!candidate || typeof candidate !== "object") {
      return defaultEngines[0];
    }

    return defaultEngines.find(({ url, img }) => url === candidate.thisSearch && img === candidate.thisSearchIcon)
      ?? defaultEngines.find(({ url }) => url === candidate.thisSearch)
      ?? defaultEngines.find(({ img }) => img === candidate.thisSearchIcon)
      ?? defaultEngines[0];
  };

  const readSearchData = () => {
    try {
      const rawValue = localStorage.getItem(storageKey);
      if (!rawValue) {
        return getDefaultState();
      }

      const parsedValue = JSON.parse(rawValue);
      const activeEngine = resolveActiveEngine(parsedValue);

      return {
        thisSearch: activeEngine.url,
        thisSearchIcon: activeEngine.img,
        data: defaultEngines.map((engine) => ({ ...engine }))
      };
    } catch {
      return getDefaultState();
    }
  };

  let searchData = readSearchData();
  let hideTimerId = 0;

  const persistSearchData = () => {
    try {
      localStorage.setItem(storageKey, JSON.stringify(searchData));
    } catch {
      // localStorage can be unavailable in privacy modes or local file contexts.
    }
  };

  const setSearchIcon = () => {
    const activeEngine = resolveActiveEngine(searchData);
    searchIcon.src = activeEngine.img;
    searchIcon.alt = "";
    searchToggle.setAttribute("aria-label", `当前搜索引擎：${activeEngine.name}。点击切换`);
  };

  const showSearchEngines = () => {
    window.clearTimeout(hideTimerId);
    searchEnginePanel.hidden = false;
    searchToggle.setAttribute("aria-expanded", "true");
  };

  const hideSearchEngines = () => {
    window.clearTimeout(hideTimerId);
    searchEnginePanel.hidden = true;
    searchToggle.setAttribute("aria-expanded", "false");
  };

  const scheduleHideSearchEngines = () => {
    window.clearTimeout(hideTimerId);
    hideTimerId = window.setTimeout(() => {
      if (!searchEnginePanel.matches(":hover") && !searchToggle.matches(":hover")) {
        hideSearchEngines();
      }
    }, 150);
  };

  const openSearch = () => {
    const keyword = searchInput.value.trim();
    if (!keyword) {
      searchInput.focus();
      return;
    }

    const targetUrl = `${searchData.thisSearch}${encodeURIComponent(keyword)}`;
    const openedWindow = window.open(targetUrl, "_blank", "noopener,noreferrer");

    if (openedWindow) {
      openedWindow.opener = null;
    }
  };

  const renderSearchEngines = () => {
    const fragment = document.createDocumentFragment();

    searchData.data.forEach((engine, index) => {
      const listItem = document.createElement("li");
      const option = document.createElement("button");
      const icon = document.createElement("img");

      option.type = "button";
      option.className = "search-engine-option";
      option.dataset.index = String(index);
      option.setAttribute("aria-label", `切换到${engine.name}`);

      icon.src = engine.img;
      icon.alt = "";
      icon.loading = "lazy";
      icon.decoding = "async";

      option.append(icon, document.createTextNode(engine.name));
      listItem.append(option);
      fragment.append(listItem);
    });

    searchEngineList.replaceChildren(fragment);
  };

  const setActiveEngine = (index) => {
    const engine = searchData.data[index];
    if (!engine) {
      return;
    }

    searchData.thisSearch = engine.url;
    searchData.thisSearchIcon = engine.img;
    setSearchIcon();
    persistSearchData();
  };

  searchInput.addEventListener("keydown", (event) => {
    if (event.key === "Enter") {
      openSearch();
    }
  });

  searchButton.addEventListener("click", openSearch);

  searchToggle.addEventListener("mouseenter", showSearchEngines);
  searchToggle.addEventListener("mouseleave", scheduleHideSearchEngines);
  searchToggle.addEventListener("click", () => {
    if (!searchEnginePanel.hidden) {
      hideSearchEngines();
      return;
    }

    showSearchEngines();
  });

  searchEnginePanel.addEventListener("mouseenter", showSearchEngines);
  searchEnginePanel.addEventListener("mouseleave", hideSearchEngines);

  searchEngineList.addEventListener("click", (event) => {
    const option = event.target.closest("button[data-index]");
    if (!option) {
      return;
    }

    setActiveEngine(Number.parseInt(option.dataset.index, 10));
    hideSearchEngines();
    searchInput.focus();
  });

  document.addEventListener("click", (event) => {
    if (searchToggle.contains(event.target) || searchEnginePanel.contains(event.target)) {
      return;
    }

    hideSearchEngines();
  });

  renderSearchEngines();
  setSearchIcon();
  hideSearchEngines();
})();
